/**
 * POST /v1/billing/checkout
 *
 * Creates a Stripe Checkout Session for the authenticated user and returns
 * the redirect URL. Handles both subscriptions (mode: "subscription") and
 * one-time purchases (mode: "payment"), chosen automatically from the
 * resolved Price's `priceType`.
 *
 * Ensures a Stripe Customer exists for the user (creates one on first use).
 */
import { route, ok, badRequest, notFound } from "@parcae/backend";
import { stripe } from "../lib/stripe";
import { requireBillingAuth } from "../lib/auth";
import { Price } from "../models/billing/Price";
import { Customer } from "../models/billing/Customer";
import { upsertCustomer } from "../lib/sync";

interface CheckoutBody {
  /** Parcae Price ID (our local id, not the stripePriceId). Required if no `priceId`. */
  price?: string;
  /** Stripe price ID (price_...). Alternative to `price`. */
  priceId?: string;
  /** Quantity (for seat-based subscriptions). Default 1. */
  quantity?: number;
  /** Promotion code string (e.g. "SUMMER20"). */
  promotionCode?: string;
  /** Override the success / cancel redirect URLs. */
  successUrl?: string;
  cancelUrl?: string;
  /** Metadata attached to the Stripe Checkout Session + resulting Subscription/Invoice. */
  metadata?: Record<string, string>;
}

route.post(
  "/v1/billing/checkout",
  requireBillingAuth,
  async (req: any, res: any) => {
    const body = (req.body ?? {}) as CheckoutBody;
    const userId: string = req.userId;

    // Resolve the Price
    let stripePriceId = body.priceId;
    let priceType: "recurring" | "one_time" = "recurring";

    if (body.price && !stripePriceId) {
      const price = await (Price as any).where({ id: body.price }).first();
      if (!price) {
        notFound(res, "Price not found");
        return;
      }
      stripePriceId = price.stripePriceId;
      priceType = price.priceType ?? "recurring";
    } else if (stripePriceId) {
      // Optional fidelity: look up local Price by stripePriceId to determine mode
      const localPrice = await (Price as any).where({ stripePriceId }).first();
      priceType = localPrice?.priceType ?? "recurring";
    } else {
      badRequest(res, "Must provide `price` or `priceId`");
      return;
    }

    // Ensure local Customer exists (lazily create the Stripe Customer too)
    const s = stripe();
    let customer = await (Customer as any).where({ user: userId }).first();
    if (!customer) {
      const email = req.session?.user?.email ?? "";
      const name = req.session?.user?.name ?? "";
      const stripeCustomer = await s.customers.create({
        email,
        name,
        metadata: { user: userId },
      });
      customer = await upsertCustomer(stripeCustomer, userId, "checkout");
    }

    // Build session params
    const successUrl =
      body.successUrl ||
      process.env.STRIPE_SUCCESS_URL ||
      `${process.env.FRONTEND_URL ?? ""}/settings/billing?success=1`;
    const cancelUrl =
      body.cancelUrl ||
      process.env.STRIPE_CANCEL_URL ||
      `${process.env.FRONTEND_URL ?? ""}/settings/billing?cancel=1`;

    const sessionParams: any = {
      customer: customer.stripeCustomerId,
      mode: priceType === "recurring" ? "subscription" : "payment",
      line_items: [
        {
          price: stripePriceId,
          quantity: body.quantity ?? 1,
        },
      ],
      success_url: successUrl,
      cancel_url: cancelUrl,
      metadata: { ...(body.metadata ?? {}), user: userId },
      allow_promotion_codes: true,
    };

    if (body.promotionCode) {
      // Resolve the code to a Stripe promotion_code ID
      const promos = await s.promotionCodes.list({
        code: body.promotionCode,
        active: true,
        limit: 1,
      });
      if (promos.data[0]) {
        sessionParams.discounts = [{ promotion_code: promos.data[0].id }];
        delete sessionParams.allow_promotion_codes;
      }
    }

    const session = await s.checkout.sessions.create(sessionParams);

    ok(res, { url: session.url, id: session.id });
  },
);

/**
 * POST /v1/billing/portal
 *
 * Creates a Stripe Customer Portal session for the authenticated user and
 * returns the redirect URL. The portal lets users self-serve payment method
 * updates, invoice downloads, plan changes, and cancellation.
 */
import { route, ok, notFound } from "@parcae/backend";
import { stripe } from "../lib/stripe";
import { requireBillingAuth } from "../lib/auth";
import { Customer } from "../models/billing/Customer";

interface PortalBody {
  /** Where Stripe returns the user after they close the portal. */
  returnUrl?: string;
  /** Optional configuration ID for a branded/themed portal. */
  configuration?: string;
}

route.post(
  "/v1/billing/portal",
  requireBillingAuth,
  async (req: any, res: any) => {
    const body = (req.body ?? {}) as PortalBody;
    const userId: string = req.userId;

    const customer = await (Customer as any).where({ user: userId }).first();
    if (!customer?.stripeCustomerId) {
      notFound(res, "No Stripe customer found for user");
      return;
    }

    const returnUrl =
      body.returnUrl ||
      process.env.STRIPE_PORTAL_RETURN_URL ||
      `${process.env.FRONTEND_URL ?? ""}/settings/billing`;

    const s = stripe();
    const session = await s.billingPortal.sessions.create({
      customer: customer.stripeCustomerId,
      return_url: returnUrl,
      configuration: body.configuration,
    });

    ok(res, { url: session.url });
  },
);

/**
 * Subscription management endpoints.
 *
 *   POST /v1/billing/subscription/cancel  — cancel at period end (or immediately)
 *   POST /v1/billing/subscription/resume  — un-cancel a pending cancellation
 *   POST /v1/billing/subscription/change  — swap to a new Price (upgrade/downgrade)
 *
 * All operations call the Stripe API directly; webhooks will then sync the
 * updated subscription back to our local Subscription Model. In the meantime
 * we can optimistically update local state for snappy UI (but we skip that
 * here for simplicity — realtime diffs will arrive within a second).
 */
import { route, ok, notFound, badRequest } from "@parcae/backend";
import { stripe } from "../lib/stripe";
import { requireBillingAuth } from "../lib/auth";
import { Subscription } from "../models/billing/Subscription";
import { SubscriptionItem } from "../models/billing/SubscriptionItem";
import { Price } from "../models/billing/Price";

async function getOwnedSubscription(
  subscriptionId: string,
  userId: string,
  res: any,
): Promise<any> {
  const sub = await (Subscription as any)
    .where({ id: subscriptionId, user: userId })
    .first();
  if (!sub) {
    notFound(res, "Subscription not found");
    return null;
  }
  return sub;
}

// ─── POST /v1/billing/subscription/cancel ────────────────────────────────────

route.post(
  "/v1/billing/subscription/cancel",
  requireBillingAuth,
  async (req: any, res: any) => {
    const { subscription, immediate, feedback, comment } = req.body ?? {};
    if (!subscription) {
      badRequest(res, "Missing `subscription` (id)");
      return;
    }

    const sub = await getOwnedSubscription(subscription, req.userId, res);
    if (!sub) return;

    const s = stripe();
    if (immediate) {
      const canceled = await s.subscriptions.cancel(sub.stripeSubscriptionId, {
        cancellation_details: { comment, feedback },
      });
      ok(res, { status: canceled.status });
    } else {
      const updated = await s.subscriptions.update(sub.stripeSubscriptionId, {
        cancel_at_period_end: true,
        cancellation_details: { comment, feedback },
      });
      ok(res, {
        status: updated.status,
        cancelAt: (updated as any).cancel_at,
      });
    }
  },
);

// ─── POST /v1/billing/subscription/resume ────────────────────────────────────

route.post(
  "/v1/billing/subscription/resume",
  requireBillingAuth,
  async (req: any, res: any) => {
    const { subscription } = req.body ?? {};
    if (!subscription) {
      badRequest(res, "Missing `subscription` (id)");
      return;
    }

    const sub = await getOwnedSubscription(subscription, req.userId, res);
    if (!sub) return;

    const s = stripe();
    const updated = await s.subscriptions.update(sub.stripeSubscriptionId, {
      cancel_at_period_end: false,
    });

    ok(res, { status: updated.status });
  },
);

// ─── POST /v1/billing/subscription/change ────────────────────────────────────

route.post(
  "/v1/billing/subscription/change",
  requireBillingAuth,
  async (req: any, res: any) => {
    const {
      subscription,
      price: newPriceId,
      quantity,
      prorationBehavior,
    } = req.body ?? {};

    if (!subscription || !newPriceId) {
      badRequest(res, "Missing `subscription` or `price`");
      return;
    }

    const sub = await getOwnedSubscription(subscription, req.userId, res);
    if (!sub) return;

    // Resolve new Price to stripePriceId
    const newPrice = await (Price as any).where({ id: newPriceId }).first();
    if (!newPrice) {
      notFound(res, "Price not found");
      return;
    }

    // Find the first SubscriptionItem (single-item subscription assumption)
    const item = await (SubscriptionItem as any)
      .where({ subscription: sub.id })
      .first();

    if (!item) {
      badRequest(res, "Subscription has no items to change");
      return;
    }

    const s = stripe();
    const updated = await s.subscriptions.update(sub.stripeSubscriptionId, {
      items: [
        {
          id: item.stripeSubscriptionItemId,
          price: newPrice.stripePriceId,
          quantity: quantity ?? item.quantity ?? 1,
        },
      ],
      proration_behavior: prorationBehavior ?? "create_prorations",
    });

    ok(res, { status: updated.status });
  },
);

/**
 * POST /v1/billing/usage
 *
 * Report usage events against a Stripe Meter (metered billing). The body
 * payload mirrors Stripe's Meter Events shape; we wrap it with auth +
 * customer resolution + local UsageRecord persistence for audit trails.
 *
 *   body: { meter: "mtr_...", quantity: 1, timestamp?: iso, idempotencyKey?: string, payload?: {...} }
 */
import { route, ok, badRequest } from "@parcae/backend";
import { stripe } from "../lib/stripe";
import { requireBillingAuth } from "../lib/auth";
import { Customer } from "../models/billing/Customer";
import { Meter } from "../models/billing/Meter";
import { UsageRecord } from "../models/billing/UsageRecord";

interface UsageBody {
  /** Meter event name (e.g. "api_request") — matches Meter.eventName. */
  event: string;
  /** Quantity to report. */
  quantity: number;
  /** Unix timestamp (seconds). Defaults to now. */
  timestamp?: number;
  /** Idempotency key — stable string so duplicates are rejected by Stripe. */
  idempotencyKey?: string;
  /** Any extra payload Stripe should receive on the meter event. */
  payload?: Record<string, any>;
}

route.post(
  "/v1/billing/usage",
  requireBillingAuth,
  async (req: any, res: any) => {
    const body = (req.body ?? {}) as UsageBody;
    const userId: string = req.userId;

    if (!body.event || typeof body.quantity !== "number") {
      badRequest(res, "Must provide `event` and numeric `quantity`");
      return;
    }

    const customer = await (Customer as any).where({ user: userId }).first();
    if (!customer?.stripeCustomerId) {
      badRequest(res, "User has no Stripe customer");
      return;
    }

    const meter = await (Meter as any).where({ eventName: body.event }).first();
    if (!meter) {
      badRequest(res, `Unknown meter event: ${body.event}`);
      return;
    }

    const ts = body.timestamp ?? Math.floor(Date.now() / 1000);

    // Send to Stripe — Meter Events API
    const s = stripe();
    await (s as any).billing.meterEvents.create(
      {
        event_name: body.event,
        timestamp: ts,
        payload: {
          value: String(body.quantity),
          stripe_customer_id: customer.stripeCustomerId,
          ...(body.payload ?? {}),
        },
        ...(body.idempotencyKey && { identifier: body.idempotencyKey }),
      },
      body.idempotencyKey ? { idempotencyKey: body.idempotencyKey } : undefined,
    );

    // Record locally for audit/dashboard
    const record = (UsageRecord as any).create({
      user: userId,
      meter: meter.id,
      quantity: body.quantity,
      timestamp: new Date(ts * 1000),
      idempotencyKey: body.idempotencyKey ?? "",
      action: "increment",
    });
    await record.save();

    ok(res, { recorded: true });
  },
);

/**
 * POST /v1/billing/webhook
 *
 * Stripe webhook receiver. Verifies the signature, parses the event, and
 * dispatches to event handlers. Replies 200 to ACK receipt — Stripe retries
 * on 4xx/5xx/timeouts.
 *
 * Registered at `priority: 1` so it runs before any global JSON body parser
 * — webhook signature verification requires the raw request body.
 */
import { route, json, error as errorRes } from "@parcae/backend";
import { log } from "@parcae/backend";
import type Stripe from "stripe";
import { stripe } from "../lib/stripe";
import { captureRawBody, resolveRawBody } from "../lib/raw-body";
import { dispatchStripeEvent } from "../events";

route.post(
  "/v1/billing/webhook",
  captureRawBody,
  async (req: any, res: any) => {
    const sig = req.headers["stripe-signature"] as string | undefined;
    const secret = process.env.STRIPE_WEBHOOK_SECRET;
    const skipVerify = process.env.STRIPE_SKIP_SIGNATURE_VERIFY === "1";

    if (!secret && !skipVerify) {
      log.error(
        "[billing/webhook] STRIPE_WEBHOOK_SECRET is not set. Set it or STRIPE_SKIP_SIGNATURE_VERIFY=1 for local dev.",
      );
      errorRes(res, 500, "Webhook secret not configured");
      return;
    }

    let event: Stripe.Event;
    try {
      if (skipVerify) {
        // Dev-only path — parse whatever body we have
        event = (req.body ??
          JSON.parse(await resolveRawBody(req))) as Stripe.Event;
      } else {
        if (!sig) {
          log.warn("[billing/webhook] Missing stripe-signature header");
          errorRes(res, 400, "Missing stripe-signature header");
          return;
        }
        const raw = await resolveRawBody(req);
        event = stripe().webhooks.constructEvent(raw, sig, secret!);
      }
    } catch (err: any) {
      log.warn(
        `[billing/webhook] Signature verification failed: ${err.message}`,
      );
      errorRes(
        res,
        400,
        `Webhook signature verification failed: ${err.message}`,
      );
      return;
    }

    // ACK immediately in parallel with dispatch (Stripe wants fast 200s).
    // We still await dispatch because Parcae's socket-RPC bridge needs end()
    // to fire to send the response. For high-volume webhooks consider
    // enqueuing dispatch into a BullMQ job instead of awaiting here.
    try {
      await dispatchStripeEvent(event);
    } catch (err: any) {
      // We already logged inside dispatch. Return 500 so Stripe retries.
      errorRes(res, 500, "Event dispatch failed");
      return;
    }

    json(res, 200, { received: true, id: event.id });
  },
  { priority: 1 },
);

import type Stripe from "stripe";
import { log } from "@parcae/backend";
import { stripe } from "../lib/stripe";
import { upsertCustomer, upsertSubscription, upsertInvoice } from "../lib/sync";

/**
 * Checkout sessions roll up multiple downstream objects: Customer created,
 * Subscription created (for recurring) or Invoice paid (for one-time). We
 * re-fetch each one so we have the fully expanded object, then upsert.
 */
export async function handleCheckoutEvent(event: Stripe.Event): Promise<void> {
  const session = event.data.object as Stripe.Checkout.Session;
  const client = stripe();

  switch (event.type) {
    case "checkout.session.completed":
    case "checkout.session.async_payment_succeeded": {
      // Customer: embedded or by ID
      if (session.customer) {
        const id =
          typeof session.customer === "string"
            ? session.customer
            : session.customer.id;
        const customer = await client.customers.retrieve(id);
        const appUserId =
          session.metadata?.user ?? session.metadata?.userId ?? null;
        await upsertCustomer(
          customer as Stripe.Customer,
          appUserId,
          `webhook:${event.type}`,
        );
      }

      // Recurring: sync the created subscription
      if (session.subscription) {
        const subId =
          typeof session.subscription === "string"
            ? session.subscription
            : session.subscription.id;
        const sub = await client.subscriptions.retrieve(subId, {
          expand: ["items"],
        });
        await upsertSubscription(sub, `webhook:${event.type}`);
      }

      // One-time: sync the resulting invoice
      if (session.invoice) {
        const invId =
          typeof session.invoice === "string"
            ? session.invoice
            : session.invoice.id;
        if (invId) {
          const inv = await client.invoices.retrieve(invId);
          await upsertInvoice(inv, `webhook:${event.type}`);
        }
      }

      log.info(`[billing] ${event.type} session=${session.id}`);
      break;
    }

    case "checkout.session.async_payment_failed":
    case "checkout.session.expired":
      log.info(`[billing] ${event.type} session=${session.id}`);
      break;

    default:
      log.info(`[billing] Unhandled checkout event: ${event.type}`);
  }
}

import type Stripe from "stripe";
import { log } from "@parcae/backend";
import { upsertCustomer } from "../lib/sync";

export async function handleCustomerEvent(event: Stripe.Event): Promise<void> {
  const customer = event.data.object as
    | Stripe.Customer
    | Stripe.DeletedCustomer;

  switch (event.type) {
    case "customer.created":
    case "customer.updated":
    case "customer.deleted":
      await upsertCustomer(customer, null, `webhook:${event.type}`);
      log.info(`[billing] ${event.type} ${customer.id}`);
      break;

    default:
      log.info(`[billing] Unhandled customer event: ${event.type}`);
  }
}

import type Stripe from "stripe";
import { log } from "@parcae/backend";
import { handleProductEvent } from "./product";
import { handlePriceEvent } from "./price";
import { handleCustomerEvent } from "./customer";
import { handleSubscriptionEvent } from "./subscription";
import { handleInvoiceEvent } from "./invoice";
import { handleCheckoutEvent } from "./checkout";
import { handlePaymentMethodEvent } from "./payment-method";
import { upsertCoupon, upsertPromotionCode } from "../lib/sync";

/**
 * Dispatches a Stripe event to the appropriate handler based on prefix.
 *
 * Unknown events are logged but don't throw — Stripe will add new event
 * types over time and we want our server to keep running.
 */
export async function dispatchStripeEvent(event: Stripe.Event): Promise<void> {
  const prefix = event.type.split(".")[0];

  try {
    switch (prefix) {
      case "product":
        await handleProductEvent(event);
        break;

      case "price":
        await handlePriceEvent(event);
        break;

      case "customer":
        if (event.type.startsWith("customer.subscription.")) {
          await handleSubscriptionEvent(event);
        } else {
          await handleCustomerEvent(event);
        }
        break;

      case "invoice":
        await handleInvoiceEvent(event);
        break;

      case "checkout":
        await handleCheckoutEvent(event);
        break;

      case "payment_method":
        await handlePaymentMethodEvent(event);
        break;

      case "coupon":
        if (
          event.type === "coupon.created" ||
          event.type === "coupon.updated" ||
          event.type === "coupon.deleted"
        ) {
          await upsertCoupon(
            event.data.object as Stripe.Coupon,
            `webhook:${event.type}`,
          );
        }
        break;

      case "promotion_code":
        if (
          event.type === "promotion_code.created" ||
          event.type === "promotion_code.updated"
        ) {
          await upsertPromotionCode(
            event.data.object as Stripe.PromotionCode,
            `webhook:${event.type}`,
          );
        }
        break;

      default:
        log.info(
          `[billing] Unhandled event prefix: ${prefix} (${event.type})`,
        );
    }
  } catch (err: any) {
    log.error(
      `[billing] Event handler threw for ${event.type}: ${err.message}`,
      err,
    );
    throw err;
  }
}

import type Stripe from "stripe";
import { log } from "@parcae/backend";
import { upsertInvoice } from "../lib/sync";

export async function handleInvoiceEvent(event: Stripe.Event): Promise<void> {
  const invoice = event.data.object as Stripe.Invoice;

  switch (event.type) {
    case "invoice.created":
    case "invoice.finalized":
    case "invoice.paid":
    case "invoice.payment_succeeded":
    case "invoice.payment_failed":
    case "invoice.voided":
    case "invoice.marked_uncollectible":
    case "invoice.upcoming":
      await upsertInvoice(invoice, `webhook:${event.type}`);
      log.info(
        `[billing] ${event.type} ${invoice.id} (${invoice.amount_paid}/${invoice.amount_due} ${invoice.currency})`,
      );
      break;

    default:
      log.info(`[billing] Unhandled invoice event: ${event.type}`);
  }
}

import type Stripe from "stripe";
import { log } from "@parcae/backend";
import { upsertPaymentMethod } from "../lib/sync";
import { PaymentMethod } from "../models/billing/PaymentMethod";
import { runInSyncContext } from "../lib/sync-context";

export async function handlePaymentMethodEvent(
  event: Stripe.Event,
): Promise<void> {
  const pm = event.data.object as Stripe.PaymentMethod;

  switch (event.type) {
    case "payment_method.attached":
    case "payment_method.updated":
    case "payment_method.automatically_updated":
      await upsertPaymentMethod(pm, `webhook:${event.type}`);
      log.info(`[billing] ${event.type} ${pm.id}`);
      break;

    case "payment_method.detached":
      await runInSyncContext(`webhook:${event.type}`, async () => {
        const local = await (PaymentMethod as any)
          .where({ stripePaymentMethodId: pm.id })
          .first();
        if (local) {
          await local.remove();
        }
      });
      log.info(`[billing] ${event.type} ${pm.id}`);
      break;

    default:
      log.info(`[billing] Unhandled payment_method event: ${event.type}`);
  }
}

import type Stripe from "stripe";
import { log } from "@parcae/backend";
import { upsertPrice } from "../lib/sync";
import { Price } from "../models/billing/Price";
import { runInSyncContext } from "../lib/sync-context";

export async function handlePriceEvent(event: Stripe.Event): Promise<void> {
  const price = event.data.object as Stripe.Price;

  switch (event.type) {
    case "price.created":
    case "price.updated":
      await upsertPrice(price, `webhook:${event.type}`);
      log.info(`[billing] ${event.type} ${price.id}`);
      break;

    case "price.deleted":
      await runInSyncContext(`webhook:${event.type}`, async () => {
        const local = await (Price as any)
          .where({ stripePriceId: price.id })
          .first();
        if (local) {
          local.active = false;
          local.lastSyncedAt = new Date();
          await local.save();
        }
      });
      log.info(`[billing] ${event.type} ${price.id}`);
      break;

    default:
      log.info(`[billing] Unhandled price event: ${event.type}`);
  }
}

/**
 * Stripe product.* event handlers.
 *
 * Invoked from the webhook controller. All sync happens inside
 * `runInSyncContext` (inside upsertProduct) so the outbound-push hook
 * short-circuits and doesn't re-emit.
 */
import type Stripe from "stripe";
import { log } from "@parcae/backend";
import { upsertProduct } from "../lib/sync";
import { Product } from "../models/billing/Product";
import { runInSyncContext } from "../lib/sync-context";

export async function handleProductEvent(event: Stripe.Event): Promise<void> {
  const product = event.data.object as Stripe.Product;

  switch (event.type) {
    case "product.created":
    case "product.updated":
      await upsertProduct(product, `webhook:${event.type}`);
      log.info(`[billing] ${event.type} ${product.id}`);
      break;

    case "product.deleted":
      await runInSyncContext(`webhook:${event.type}`, async () => {
        const local = await (Product as any)
          .where({ stripeProductId: product.id })
          .first();
        if (local) {
          local.active = false;
          local.lastSyncedAt = new Date();
          await local.save();
        }
      });
      log.info(`[billing] ${event.type} ${product.id}`);
      break;

    default:
      log.info(`[billing] Unhandled product event: ${event.type}`);
  }
}

import type Stripe from "stripe";
import { log } from "@parcae/backend";
import { upsertSubscription } from "../lib/sync";

export async function handleSubscriptionEvent(
  event: Stripe.Event,
): Promise<void> {
  const sub = event.data.object as Stripe.Subscription;

  switch (event.type) {
    case "customer.subscription.created":
    case "customer.subscription.updated":
    case "customer.subscription.deleted":
    case "customer.subscription.paused":
    case "customer.subscription.resumed":
    case "customer.subscription.trial_will_end":
      await upsertSubscription(sub, `webhook:${event.type}`);
      log.info(`[billing] ${event.type} ${sub.id} (status=${sub.status})`);
      break;

    default:
      log.info(`[billing] Unhandled subscription event: ${event.type}`);
  }
}

