/**
 * Push local Customer changes to Stripe.
 *
 * This typically runs when app code calls `customer.save()` to update
 * email, name, phone, address, or default payment method. Skipped when
 * inside a sync context.
 */
import { hook } from "@parcae/backend";
import { log } from "@parcae/backend";
import { Customer } from "../models/billing/Customer";
import { stripe } from "../lib/stripe";
import { isInSyncContext, runInSyncContext } from "../lib/sync-context";

hook.after(Customer, "save", async ({ model }: any) => {
  if (isInSyncContext()) return;

  const customer = model as any;
  const s = stripe();

  try {
    const payload: any = {
      email: customer.email || undefined,
      name: customer.name || undefined,
      phone: customer.phone || undefined,
      address: customer.address?.line1 ? customer.address : undefined,
      metadata: customer.metadata ?? {},
    };

    if (customer.defaultPaymentMethod) {
      payload.invoice_settings = {
        default_payment_method: customer.defaultPaymentMethod,
      };
    }

    if (customer.stripeCustomerId) {
      await s.customers.update(customer.stripeCustomerId, payload);
      log.info(
        `[billing] Customer pushed → Stripe ${customer.stripeCustomerId}`,
      );
    } else {
      const created = await s.customers.create({
        ...payload,
        metadata: { ...payload.metadata, user: customer.user },
      });
      await runInSyncContext("push:customer", async () => {
        customer.stripeCustomerId = created.id;
        customer.lastSyncedAt = new Date();
        await customer.save();
      });
      log.info(`[billing] Customer created in Stripe: ${created.id}`);
    }
  } catch (err: any) {
    log.error(
      `[billing] Failed to push Customer ${customer.id} to Stripe: ${err.message}`,
    );
  }
});

/**
 * Push local Price changes to Stripe.
 *
 * Stripe Prices are immutable — `unit_amount` and `currency` can't be
 * changed after creation. For amount changes, create a new Price and
 * archive the old one (the reconcile flow will link them via lookup_key).
 *
 * This hook only handles:
 * - Creating a brand-new Stripe Price from a local Price row (no stripePriceId yet)
 * - Toggling `active` on an existing Price
 * - Updating `nickname`, `metadata`, `lookup_key` (mutable fields)
 */
import { hook } from "@parcae/backend";
import { log } from "@parcae/backend";
import { Price } from "../models/billing/Price";
import { Product } from "../models/billing/Product";
import { stripe } from "../lib/stripe";
import { isInSyncContext, runInSyncContext } from "../lib/sync-context";

hook.after(Price, "save", async ({ model }: any) => {
  if (isInSyncContext()) return;

  const price = model as any;
  const s = stripe();

  try {
    if (price.stripePriceId) {
      // Only mutable fields
      await s.prices.update(price.stripePriceId, {
        nickname: price.nickname || undefined,
        active: price.active,
        metadata: price.metadata ?? {},
        lookup_key: price.lookupKey || undefined,
      });
      log.info(`[billing] Price pushed → Stripe ${price.stripePriceId}`);
      return;
    }

    // New price — we need the Stripe product ID. Resolve via local Product.
    const localProduct = price.$product
      ? await (Product as any).where({ id: price.$product }).first()
      : null;

    if (!localProduct?.stripeProductId) {
      log.warn(
        `[billing] Cannot create Stripe Price: local Price ${price.id} has no product / stripeProductId`,
      );
      return;
    }

    const isRecurring = price.priceType === "recurring";
    const created = await s.prices.create({
      product: localProduct.stripeProductId,
      unit_amount: price.unitAmount,
      currency: price.currency,
      nickname: price.nickname || undefined,
      active: price.active,
      metadata: price.metadata ?? {},
      lookup_key: price.lookupKey || undefined,
      ...(isRecurring && {
        recurring: {
          interval: price.interval ?? "month",
          interval_count: price.intervalCount ?? 1,
          usage_type: price.usageType ?? "licensed",
          ...(price.usageType === "metered" &&
            price.aggregateUsage && {
              aggregate_usage: price.aggregateUsage,
            }),
          ...(price.trialPeriodDays > 0 && {
            trial_period_days: price.trialPeriodDays,
          }),
        },
      }),
    });

    await runInSyncContext("push:price", async () => {
      price.stripePriceId = created.id;
      price.lastSyncedAt = new Date();
      await price.save();
    });
    log.info(`[billing] Price created in Stripe: ${created.id}`);
  } catch (err: any) {
    log.error(
      `[billing] Failed to push Price ${price.id} to Stripe: ${err.message}`,
    );
  }
});

/**
 * Push local Product changes to Stripe.
 *
 * Runs after every Product save. Skipped when inside a sync context
 * (i.e. the save originated from a webhook or reconcile job).
 */
import { hook } from "@parcae/backend";
import { log } from "@parcae/backend";
import { Product } from "../models/billing/Product";
import { stripe } from "../lib/stripe";
import { isInSyncContext, runInSyncContext } from "../lib/sync-context";

hook.after(Product, "save", async ({ model }: any) => {
  if (isInSyncContext()) return;

  const product = model as any;
  const s = stripe();

  try {
    const payload = {
      name: product.name,
      description: product.description || undefined,
      images: product.image ? [product.image] : undefined,
      active: product.active,
      metadata: product.metadata ?? {},
      // `features` is accepted by Stripe as a list of {name} objects
      features: (product.features ?? []).map((name: string) => ({ name })),
    };

    if (product.stripeProductId) {
      await s.products.update(product.stripeProductId, payload);
      log.info(`[billing] Product pushed → Stripe ${product.stripeProductId}`);
    } else {
      const created = await s.products.create(payload);
      // Write back the Stripe ID without re-firing this hook
      await runInSyncContext("push:product", async () => {
        product.stripeProductId = created.id;
        product.lastSyncedAt = new Date();
        await product.save();
      });
      log.info(`[billing] Product created in Stripe: ${created.id}`);
    }
  } catch (err: any) {
    log.error(
      `[billing] Failed to push Product ${product.id} to Stripe: ${err.message}`,
    );
  }
});

hook.after(Product, "remove", async ({ model }: any) => {
  if (isInSyncContext()) return;

  const product = model as any;
  if (!product.stripeProductId) return;

  try {
    // Stripe deletes products permanently only when no prices exist; otherwise
    // archive (active=false) is the convention.
    await stripe().products.update(product.stripeProductId, { active: false });
    log.info(
      `[billing] Product archived in Stripe: ${product.stripeProductId}`,
    );
  } catch (err: any) {
    log.error(`[billing] Failed to archive Product in Stripe: ${err.message}`);
  }
});

/**
 * Push local Subscription changes to Stripe.
 *
 * Subscriptions are primarily mutated via the dedicated controllers
 * (/v1/billing/subscription/*). This hook catches programmatic changes —
 * e.g. app code calling `sub.cancelAtPeriodEnd = true; await sub.save()` —
 * and mirrors them to Stripe.
 */
import { hook } from "@parcae/backend";
import { log } from "@parcae/backend";
import { Subscription } from "../models/billing/Subscription";
import { stripe } from "../lib/stripe";
import { isInSyncContext } from "../lib/sync-context";

hook.after(Subscription, "save", async ({ model }: any) => {
  if (isInSyncContext()) return;

  const sub = model as any;
  if (!sub.stripeSubscriptionId) return;

  const s = stripe();

  try {
    const payload: any = {
      metadata: sub.metadata ?? {},
      cancel_at_period_end: sub.cancelAtPeriodEnd,
    };

    if (sub.defaultPaymentMethod) {
      payload.default_payment_method = sub.defaultPaymentMethod;
    }

    if (sub.collectionMethod) {
      payload.collection_method = sub.collectionMethod;
    }

    await s.subscriptions.update(sub.stripeSubscriptionId, payload);
    log.info(
      `[billing] Subscription pushed → Stripe ${sub.stripeSubscriptionId}`,
    );
  } catch (err: any) {
    log.error(
      `[billing] Failed to push Subscription ${sub.id} to Stripe: ${err.message}`,
    );
  }
});

/**
 * billing:reconcile — daily safety-net sync.
 *
 * Walks all known Stripe customer/subscription/invoice/product/price IDs
 * and pulls their current state from Stripe. Covers webhook drops, network
 * hiccups, and bulk Dashboard edits that outran our webhook endpoint.
 *
 * Schedule this with your own cron / queue scheduler — e.g.:
 *
 *   await enqueue("billing:reconcile", {}, {
 *     repeat: { cron: "0 3 * * *" },  // 3am daily
 *     jobId: "billing:reconcile",     // dedupe
 *   });
 */
import { job } from "@parcae/backend";
import { log } from "@parcae/backend";
import { stripe } from "../lib/stripe";
import {
  upsertProduct,
  upsertPrice,
  upsertCustomer,
  upsertSubscription,
  upsertInvoice,
  upsertCoupon,
  upsertPromotionCode,
} from "../lib/sync";

async function reconcileProducts() {
  const s = stripe();
  let count = 0;
  for await (const p of s.products.list({ limit: 100 })) {
    await upsertProduct(p, "reconcile");
    count++;
  }
  return count;
}

async function reconcilePrices() {
  const s = stripe();
  let count = 0;
  for await (const p of s.prices.list({ limit: 100 })) {
    await upsertPrice(p, "reconcile");
    count++;
  }
  return count;
}

async function reconcileCoupons() {
  const s = stripe();
  let count = 0;
  for await (const c of s.coupons.list({ limit: 100 })) {
    await upsertCoupon(c, "reconcile");
    count++;
  }
  return count;
}

async function reconcilePromotionCodes() {
  const s = stripe();
  let count = 0;
  for await (const pc of s.promotionCodes.list({ limit: 100 })) {
    await upsertPromotionCode(pc, "reconcile");
    count++;
  }
  return count;
}

async function reconcileCustomersAndSubscriptions() {
  const s = stripe();
  let customerCount = 0;
  let subCount = 0;

  for await (const c of s.customers.list({ limit: 100 })) {
    await upsertCustomer(c, null, "reconcile");
    customerCount++;

    for await (const sub of s.subscriptions.list({
      customer: c.id,
      status: "all",
      limit: 100,
    })) {
      await upsertSubscription(sub, "reconcile");
      subCount++;
    }
  }

  return { customerCount, subCount };
}

async function reconcileInvoices() {
  const s = stripe();
  // Window: last 90 days. Tune as needed — older invoices rarely change.
  const since = Math.floor(Date.now() / 1000) - 60 * 60 * 24 * 90;
  let count = 0;
  for await (const inv of s.invoices.list({
    created: { gte: since },
    limit: 100,
  })) {
    await upsertInvoice(inv, "reconcile");
    count++;
  }
  return count;
}

job("billing:reconcile", async () => {
  log.info("[billing:reconcile] Starting");

  const products = await reconcileProducts();
  const prices = await reconcilePrices();
  const coupons = await reconcileCoupons();
  const promotionCodes = await reconcilePromotionCodes();
  const { customerCount, subCount } =
    await reconcileCustomersAndSubscriptions();
  const invoices = await reconcileInvoices();

  log.info(
    `[billing:reconcile] Done — products=${products}, prices=${prices}, ` +
      `coupons=${coupons}, promos=${promotionCodes}, customers=${customerCount}, ` +
      `subs=${subCount}, invoices=${invoices}`,
  );

  return {
    products,
    prices,
    coupons,
    promotionCodes,
    customers: customerCount,
    subscriptions: subCount,
    invoices,
  };
});

/**
 * Minimal auth middleware for billing routes.
 *
 * Relies on `req.session.user.id` being set by your Parcae auth adapter
 * (either @parcae/auth-betterauth or @parcae/auth-clerk). We keep this
 * local to the billing package so consumers don't have to wire a cross-
 * cutting `@/utilities/auth` import.
 */
import { unauthorized } from "@parcae/backend";

/**
 * Polka/Express middleware. Sets `req.userId` when authenticated,
 * responds 401 otherwise.
 */
export function requireBillingAuth(req: any, res: any, next: () => void): void {
  const userId = req.session?.user?.id;
  if (!userId) {
    unauthorized(res);
    return;
  }
  req.userId = userId;
  next();
}

/**
 * Raw body middleware for the Stripe webhook route.
 *
 * Stripe signs the raw request body. Parcae / Polka may already have parsed
 * the body into `req.body` (JSON) before our handler runs, which loses the
 * exact byte sequence Stripe signed.
 *
 * Strategy:
 * 1. If a raw body is already available (req.rawBody Buffer, or req is still
 *    an unread Readable stream), capture it directly.
 * 2. Otherwise, fall back to `JSON.stringify(req.body)` — matches what
 *    Stripe signed in practice (since Stripe sends compact JSON with no
 *    extra whitespace). The env flag STRIPE_WEBHOOK_ALLOW_RECONSTRUCTED
 *    must be "true" to enable this fallback, since it's slightly less
 *    strict than byte-exact verification.
 *
 * In dev you can also set STRIPE_SKIP_SIGNATURE_VERIFY=1 to bypass entirely.
 */

export interface RawBodyRequest {
  rawBody?: Buffer | string;
  body?: any;
  headers: Record<string, any>;
  on?: (event: string, cb: (chunk: any) => void) => void;
  readable?: boolean;
}

/**
 * Resolve the raw request body as a string — using whichever source is
 * available. Must be called before the JSON body parser consumes the stream.
 */
export async function resolveRawBody(req: RawBodyRequest): Promise<string> {
  // 1. Prefer an explicitly captured raw body
  if (req.rawBody) {
    return Buffer.isBuffer(req.rawBody)
      ? req.rawBody.toString("utf8")
      : req.rawBody;
  }

  // 2. If the request is still readable, drain it now (rare — most middleware
  //    has already consumed it by the time our handler runs).
  if (req.readable && typeof req.on === "function") {
    const chunks: Buffer[] = [];
    await new Promise<void>((resolve, reject) => {
      req.on!("data", (c: Buffer | string) =>
        chunks.push(typeof c === "string" ? Buffer.from(c) : c),
      );
      req.on!("end", () => resolve());
      req.on!("error", (err: Error) => reject(err));
    });
    const raw = Buffer.concat(chunks).toString("utf8");
    req.rawBody = raw;
    return raw;
  }

  // 3. Fallback: reconstruct from parsed body. Feature-flagged because it's
  //    not byte-exact with what Stripe signed in edge cases.
  if (
    req.body != null &&
    process.env.STRIPE_WEBHOOK_ALLOW_RECONSTRUCTED !== "false"
  ) {
    return typeof req.body === "string" ? req.body : JSON.stringify(req.body);
  }

  throw new Error(
    "[billing/raw-body] Unable to resolve raw body for webhook signature verification. " +
      "Ensure no JSON parser middleware runs before the webhook route, or set " +
      "STRIPE_WEBHOOK_ALLOW_RECONSTRUCTED=true to fall back to JSON.stringify reconstruction.",
  );
}

/**
 * Polka/Express-style middleware that captures the raw body stream into
 * `req.rawBody`. Attach with `priority: 1` so it runs before the global
 * JSON parser. Safe to attach only for the webhook path.
 */
export function captureRawBody(
  req: any,
  _res: any,
  next: () => void,
): void | Promise<void> {
  if (req.rawBody || !req.readable) {
    next();
    return;
  }

  const chunks: Buffer[] = [];
  req.on("data", (c: Buffer | string) =>
    chunks.push(typeof c === "string" ? Buffer.from(c) : c),
  );
  req.on("end", () => {
    req.rawBody = Buffer.concat(chunks);
    next();
  });
  req.on("error", () => {
    // Let downstream handle the error response
    next();
  });
}

/**
 * Stripe SDK singleton.
 *
 * Lazy-initialized so that this file can be imported at module-load time
 * without requiring STRIPE_SECRET_KEY to already be set.
 */
import Stripe from "stripe";

let client: Stripe | null = null;

/**
 * Get the shared Stripe client. Throws if STRIPE_SECRET_KEY is unset.
 *
 * Configure once via environment — never pass the secret key through code.
 */
export function stripe(): Stripe {
  if (client) return client;

  const key = process.env.STRIPE_SECRET_KEY;
  if (!key) {
    throw new Error(
      "[billing/stripe] STRIPE_SECRET_KEY is not set. Configure it in your environment " +
        "before calling billing routes or handlers.",
    );
  }

  client = new Stripe(key, {
    // Pin a known API version. Bump intentionally.
    apiVersion: "2025-10-27.basil" as any,
    appInfo: {
      name: "parcae-billing-stripe",
      version: "0.1.0",
      url: "https://github.com/EdenCoder/parcae",
    },
    typescript: true,
  });

  return client;
}

/**
 * Reset the singleton — test-only. Calls fresh `new Stripe()` on next access.
 */
export function resetStripeClient(): void {
  client = null;
}

/**
 * Sync Context — Node AsyncLocalStorage flag that prevents webhook echo loops.
 *
 * Flow without this:
 *   Stripe webhook → events/product.ts → upsert Product → hook.after(Product, "save")
 *     → push to Stripe → Stripe fires another webhook → infinite loop.
 *
 * Flow with this:
 *   Webhook → runInSyncContext(async () => upsert Product)
 *     → hook.after(Product, "save") sees isInSyncContext() === true → no-op.
 *
 * Wrap every DB write that originates from a webhook (or from the reconcile
 * job) in `runInSyncContext`. The outbound push hooks check `isInSyncContext()`
 * and return early when true.
 */
import { AsyncLocalStorage } from "node:async_hooks";

const storage = new AsyncLocalStorage<{ source: string }>();

/**
 * Execute `fn` under a "we are currently syncing from Stripe" flag.
 * Outbound push hooks will short-circuit while this is active.
 */
export function runInSyncContext<T>(
  source: string,
  fn: () => T | Promise<T>,
): Promise<T> {
  return new Promise<T>((resolve, reject) => {
    storage.run({ source }, () => {
      Promise.resolve(fn()).then(resolve, reject);
    });
  });
}

/**
 * True while any ancestor call frame is inside `runInSyncContext`.
 */
export function isInSyncContext(): boolean {
  return storage.getStore() !== undefined;
}

/**
 * Return the sync source label ("webhook:product.created", "reconcile", etc.)
 * if we're inside a sync context — useful for debug logs.
 */
export function getSyncSource(): string | null {
  return storage.getStore()?.source ?? null;
}

/**
 * Stripe → Parcae Model sync helpers.
 *
 * Each `upsert*` function:
 * 1. Finds the local Model by its Stripe ID
 * 2. Updates fields from the Stripe object (or creates a new row)
 * 3. Runs the whole operation inside `runInSyncContext` so outbound-push
 *    hooks skip (prevents webhook echo loops)
 *
 * Shared by webhook handlers AND the reconcile job.
 */
import type Stripe from "stripe";
import { Model } from "@parcae/model";
import { log } from "@parcae/backend";
import { Product } from "../models/billing/Product";
import { Price } from "../models/billing/Price";
import { Customer } from "../models/billing/Customer";
import { Subscription } from "../models/billing/Subscription";
import { SubscriptionItem } from "../models/billing/SubscriptionItem";
import { Invoice } from "../models/billing/Invoice";
import { PaymentMethod } from "../models/billing/PaymentMethod";
import { Coupon } from "../models/billing/Coupon";
import { PromotionCode } from "../models/billing/PromotionCode";
import { runInSyncContext } from "./sync-context";

const now = () => new Date();

// ─── Helpers ─────────────────────────────────────────────────────────────────

function tsToDate(ts: number | null | undefined): Date | null {
  return ts ? new Date(ts * 1000) : null;
}

async function upsertOrCreate<T extends typeof Model>(
  ModelClass: T,
  findBy: Record<string, any>,
  defaults: Record<string, any>,
): Promise<any> {
  const ModelAny = ModelClass as any;
  let instance = await ModelAny.where(findBy).first();
  if (!instance) {
    instance = ModelAny.create(defaults);
  } else {
    for (const [k, v] of Object.entries(defaults)) {
      (instance as any)[k] = v;
    }
  }
  await instance.save();
  return instance;
}

// ─── Products ────────────────────────────────────────────────────────────────

export async function upsertProduct(
  stripeProduct: Stripe.Product | Stripe.DeletedProduct,
  source = "sync:product",
): Promise<any> {
  return runInSyncContext(source, async () => {
    if ((stripeProduct as Stripe.DeletedProduct).deleted) {
      const existing = await (Product as any)
        .where({ stripeProductId: stripeProduct.id })
        .first();
      if (existing) {
        existing.active = false;
        existing.lastSyncedAt = now();
        await existing.save();
      }
      return existing;
    }

    const p = stripeProduct as Stripe.Product;
    return upsertOrCreate(
      Product,
      { stripeProductId: p.id },
      {
        stripeProductId: p.id,
        name: p.name ?? "",
        description: p.description ?? "",
        features: (p.marketing_features ?? []).map((f: any) => f.name),
        image: p.images?.[0] ?? "",
        active: p.active,
        metadata: p.metadata ?? {},
        lastSyncedAt: now(),
      },
    );
  });
}

// ─── Prices ──────────────────────────────────────────────────────────────────

export async function upsertPrice(
  stripePrice: Stripe.Price,
  source = "sync:price",
): Promise<any> {
  return runInSyncContext(source, async () => {
    const productId =
      typeof stripePrice.product === "string"
        ? stripePrice.product
        : stripePrice.product?.id;

    const localProduct = productId
      ? await (Product as any).where({ stripeProductId: productId }).first()
      : null;

    const recurring = stripePrice.recurring;
    return upsertOrCreate(
      Price,
      { stripePriceId: stripePrice.id },
      {
        stripePriceId: stripePrice.id,
        product: localProduct?.id ?? "",
        nickname: stripePrice.nickname ?? "",
        unitAmount: stripePrice.unit_amount ?? 0,
        currency: stripePrice.currency,
        priceType: stripePrice.type,
        interval: recurring?.interval ?? "month",
        intervalCount: recurring?.interval_count ?? 1,
        usageType: recurring?.usage_type ?? "licensed",
        // aggregate_usage removed in Stripe API v22; use Meter-linked Prices instead.
        aggregateUsage: (recurring as any)?.aggregate_usage ?? "",
        trialPeriodDays: recurring?.trial_period_days ?? 0,
        lookupKey: stripePrice.lookup_key ?? "",
        active: stripePrice.active,
        metadata: stripePrice.metadata ?? {},
        tiers: stripePrice.tiers ?? [],
        tiersMode: stripePrice.tiers_mode ?? "",
        lastSyncedAt: now(),
      },
    );
  });
}

// ─── Customers ───────────────────────────────────────────────────────────────

export async function upsertCustomer(
  stripeCustomer: Stripe.Customer | Stripe.DeletedCustomer,
  userId: string | null = null,
  source = "sync:customer",
): Promise<any> {
  return runInSyncContext(source, async () => {
    if ((stripeCustomer as any).deleted) {
      const existing = await (Customer as any)
        .where({ stripeCustomerId: stripeCustomer.id })
        .first();
      if (existing) {
        existing.deleted = true;
        existing.lastSyncedAt = now();
        await existing.save();
      }
      return existing;
    }

    const c = stripeCustomer as Stripe.Customer;

    // User linkage: metadata wins, then explicit param, then existing row
    const metaUser = c.metadata?.user ?? c.metadata?.userId ?? null;
    let existing = await (Customer as any)
      .where({ stripeCustomerId: c.id })
      .first();
    const resolvedUser = existing?.user || metaUser || userId || "";

    const defaults: Record<string, any> = {
      stripeCustomerId: c.id,
      user: resolvedUser,
      email: c.email ?? "",
      name: c.name ?? "",
      phone: c.phone ?? "",
      currency: (c.currency ?? "usd").toLowerCase(),
      defaultPaymentMethod:
        (typeof c.invoice_settings?.default_payment_method === "string"
          ? c.invoice_settings.default_payment_method
          : c.invoice_settings?.default_payment_method?.id) ?? "",
      balance: c.balance ?? 0,
      address: c.address ?? {},
      metadata: c.metadata ?? {},
      deleted: false,
      lastSyncedAt: now(),
    };

    return upsertOrCreate(Customer, { stripeCustomerId: c.id }, defaults);
  });
}

// ─── Subscriptions ───────────────────────────────────────────────────────────

export async function upsertSubscription(
  stripeSub: Stripe.Subscription,
  source = "sync:subscription",
): Promise<any> {
  return runInSyncContext(source, async () => {
    const customerId =
      typeof stripeSub.customer === "string"
        ? stripeSub.customer
        : stripeSub.customer.id;

    const customer = await (Customer as any)
      .where({ stripeCustomerId: customerId })
      .first();

    if (!customer) {
      log.warn(
        `[billing/sync] Subscription ${stripeSub.id} references unknown customer ${customerId}`,
      );
    }

    const s: any = stripeSub;
    const subscription = await upsertOrCreate(
      Subscription,
      { stripeSubscriptionId: stripeSub.id },
      {
        stripeSubscriptionId: stripeSub.id,
        customer: customer?.id ?? "",
        user: customer?.user ?? "",
        status: stripeSub.status,
        currentPeriodStart: tsToDate(s.current_period_start),
        currentPeriodEnd: tsToDate(s.current_period_end),
        cancelAtPeriodEnd: stripeSub.cancel_at_period_end ?? false,
        cancelAt: tsToDate(stripeSub.cancel_at),
        canceledAt: tsToDate(stripeSub.canceled_at),
        stripeCreatedAt: tsToDate(stripeSub.created),
        trialStart: tsToDate(stripeSub.trial_start),
        trialEnd: tsToDate(stripeSub.trial_end),
        defaultPaymentMethod:
          (typeof stripeSub.default_payment_method === "string"
            ? stripeSub.default_payment_method
            : stripeSub.default_payment_method?.id) ?? "",
        collectionMethod: stripeSub.collection_method ?? "charge_automatically",
        latestInvoice:
          (typeof stripeSub.latest_invoice === "string"
            ? stripeSub.latest_invoice
            : stripeSub.latest_invoice?.id) ?? "",
        pendingUpdate: stripeSub.pending_update ?? {},
        cancellationDetails: stripeSub.cancellation_details ?? {},
        metadata: stripeSub.metadata ?? {},
        lastSyncedAt: now(),
      },
    );

    // Sync items
    for (const item of stripeSub.items?.data ?? []) {
      await upsertSubscriptionItem(item, subscription.id, source);
    }

    return subscription;
  });
}

export async function upsertSubscriptionItem(
  stripeItem: Stripe.SubscriptionItem,
  subscriptionId: string,
  source = "sync:subscription_item",
): Promise<any> {
  return runInSyncContext(source, async () => {
    const sub = await (Subscription as any)
      .where({ id: subscriptionId })
      .first();
    const priceId =
      typeof stripeItem.price === "object" ? stripeItem.price.id : "";
    const price = priceId
      ? await (Price as any).where({ stripePriceId: priceId }).first()
      : null;

    return upsertOrCreate(
      SubscriptionItem,
      { stripeSubscriptionItemId: stripeItem.id },
      {
        stripeSubscriptionItemId: stripeItem.id,
        subscription: subscriptionId,
        price: price?.id ?? "",
        user: sub?.user ?? "",
        quantity: stripeItem.quantity ?? 1,
        stripeMeterId: (stripeItem as any).metered_subscription_item_id ?? "",
        metadata: stripeItem.metadata ?? {},
        lastSyncedAt: now(),
      },
    );
  });
}

