// ─── Promotion Codes ─────────────────────────────────────────────────────────

export async function upsertPromotionCode(
  stripePromo: Stripe.PromotionCode,
  source = "sync:promotion_code",
): Promise<any> {
  return runInSyncContext(source, async () => {
    // In Stripe API v22+ the coupon moved under `promotion.coupon`.
    // Older API shapes expose it at top level.
    const promoCoupon =
      (stripePromo as any).promotion?.coupon ??
      (stripePromo as any).coupon ??
      null;
    const couponId =
      typeof promoCoupon === "string" ? promoCoupon : (promoCoupon?.id ?? "");
    const coupon = couponId
      ? await (Coupon as any).where({ stripeCouponId: couponId }).first()
      : null;

    return upsertOrCreate(
      PromotionCode,
      { stripePromotionCodeId: stripePromo.id },
      {
        stripePromotionCodeId: stripePromo.id,
        code: stripePromo.code ?? "",
        coupon: coupon?.id ?? "",
        active: stripePromo.active,
        maxRedemptions: stripePromo.max_redemptions ?? 0,
        timesRedeemed: stripePromo.times_redeemed ?? 0,
        expiresAt: tsToDate(stripePromo.expires_at),
        firstTimeTransaction:
          stripePromo.restrictions?.first_time_transaction ?? false,
        minimumAmount: stripePromo.restrictions?.minimum_amount ?? 0,
        minimumAmountCurrency: (
          stripePromo.restrictions?.minimum_amount_currency ?? "usd"
        ).toLowerCase(),
        restrictToCustomer:
          (typeof stripePromo.customer === "string"
            ? stripePromo.customer
            : stripePromo.customer?.id) ?? "",
        metadata: stripePromo.metadata ?? {},
        lastSyncedAt: now(),
      },
    );
  });
}

/**
 * Coupon — a discount rule that can be applied to subscriptions/invoices.
 *
 * Coupons are referenced by PromotionCode (the public-facing, redeemable
 * string) or directly attached to a Customer. Stripe's model treats Coupon
 * as the discount mechanic and PromotionCode as the redemption handle.
 */
import { Model } from "@parcae/model";

export type CouponDuration = "once" | "repeating" | "forever";

export class Coupon extends Model {
  static type = "coupon" as const;

  static scope = {
    read: (ctx: any) => (ctx.user ? () => {} : null),
  };

  static indexes = ["stripeCouponId", "active"];

  /** Stripe coupon ID (often matches a human-readable slug like "SUMMER20"). */
  stripeCouponId: string = "";

  /** Display name. */
  name: string = "";

  /** Percent off (0-100). Zero when using `amountOff`. */
  percentOff: number = 0;

  /** Flat amount off in minor units. Zero when using `percentOff`. */
  amountOff: number = 0;

  /** ISO 4217 currency (only meaningful for `amountOff`). */
  currency: string = "usd";

  duration: CouponDuration = "once";

  /** Only for `duration: "repeating"`: how many months the discount applies. */
  durationInMonths: number = 0;

  /** Max total redemptions (0 = unlimited). */
  maxRedemptions: number = 0;

  /** Current redemption count (Stripe-maintained). */
  timesRedeemed: number = 0;

  /** Expiration timestamp (null = never expires). */
  redeemBy: Date | null = null;

  /** Whether the coupon is still available. Mirrors Stripe `valid`. */
  active: boolean = true;

  /** Specific Product IDs this coupon applies to (empty = all products). */
  appliesToProducts: string[] = [];

  metadata: Record<string, string> = {};

  lastSyncedAt: Date | null = null;
}

/**
 * Customer — the billing-side counterpart to your User model.
 *
 * This keeps billing metadata (Stripe customer ID, tax info, default payment
 * method) separate from your User model so auth and billing concerns stay
 * decoupled. A Customer is created lazily on first checkout for a User.
 *
 * The Model ID is deliberately NOT the User ID — it's a Parcae-generated ID.
 * Look up by `user` when you want to find a user's billing record.
 */
import { Model } from "@parcae/model";

export class Customer extends Model {
  static type = "customer" as const;

  /**
   * Users read only their own customer record. No client-side writes — all
   * changes come through Stripe or Parcae server code.
   */
  static scope = {
    read: (ctx: any) =>
      ctx.user ? (qb: any) => qb.where("user", ctx.user.id) : null,
  };

  static indexes = ["user", "stripeCustomerId", "email"];

  /** Parcae User ID (foreign key to your auth-owned users table). */
  user: string = "";

  /** Stripe customer ID (cus_...). */
  stripeCustomerId: string = "";

  /** Email used for Stripe receipts (can differ from auth email). */
  email: string = "";

  /** Display name on Stripe side. */
  name: string = "";

  /** Phone number on Stripe side. */
  phone: string = "";

  /** ISO 4217 currency code for this customer's subscriptions. */
  currency: string = "usd";

  /** Default Stripe PaymentMethod ID. */
  defaultPaymentMethod: string = "";

  /** Balance on Stripe (in minor units). Negative = credit, positive = amount owed. */
  balance: number = 0;

  /** Billing address (kept as opaque JSONB — matches Stripe.Address). */
  address: Record<string, any> = {};

  /** Tax IDs (EU VAT, etc.) registered with Stripe. */
  taxIds: any[] = [];

  /** Customer-scoped metadata that round-trips to Stripe. */
  metadata: Record<string, string> = {};

  /** Whether the customer has been deleted in Stripe. */
  deleted: boolean = false;

  lastSyncedAt: Date | null = null;
}

/**
 * Invoice — a billing record from Stripe.
 *
 * Primary driver for the "invoice history" UI and downstream features like
 * credit grants on `invoice.paid`. Never written client-side.
 */
import { Model } from "@parcae/model";
import { Customer } from "./Customer";

export type InvoiceStatus =
  | "draft"
  | "open"
  | "paid"
  | "uncollectible"
  | "void";

export class Invoice extends Model {
  static type = "invoice" as const;

  static scope = {
    read: (ctx: any) =>
      ctx.user ? (qb: any) => qb.where("user", ctx.user.id) : null,
  };

  static indexes = [
    "user",
    "customer",
    "subscription",
    "stripeInvoiceId",
    "status",
    ["user", "status"],
  ];

  user: string = "";
  customer!: Customer;

  /** Source Subscription ID (empty for one-time charges). */
  subscription: string = "";

  /** Stripe invoice ID (in_...). */
  stripeInvoiceId: string = "";

  /** Human-readable invoice number assigned by Stripe. */
  number: string = "";

  status: InvoiceStatus = "draft";

  /** Amount in minor units. */
  amountDue: number = 0;
  amountPaid: number = 0;
  amountRemaining: number = 0;

  /** Total in minor units (after discounts, including tax). */
  total: number = 0;

  /** Subtotal (before tax). */
  subtotal: number = 0;

  /** ISO 4217 currency, lowercase. */
  currency: string = "usd";

  /** Hosted invoice URL (Stripe-hosted payment page). */
  hostedInvoiceUrl: string = "";

  /** Direct PDF download URL. */
  invoicePdf: string = "";

  /** When the invoice was finalized (null for drafts). */
  finalizedAt: Date | null = null;

  /** When the invoice was paid (null if unpaid). */
  paidAt: Date | null = null;

  /** Due date (for send_invoice collection method). */
  dueDate: Date | null = null;

  /** Period covered by this invoice. */
  periodStart: Date | null = null;
  periodEnd: Date | null = null;

  /** Line items (opaque JSONB — use stripe.invoices.retrieve for detail). */
  lines: any[] = [];

  /** Description shown to the customer. */
  description: string = "";

  metadata: Record<string, string> = {};

  lastSyncedAt: Date | null = null;
}

/**
 * Meter — a Stripe Billing Meter for usage-based pricing.
 *
 * A Meter defines how raw usage events (e.g. "api_request") are aggregated
 * (sum, count, last_during_period) into billable quantities. Prices with
 * `usageType: "metered"` reference a Meter.
 *
 * Server-only — no client read scope.
 */
import { Model } from "@parcae/model";

export type MeterAggregation = "sum" | "count" | "last_during_period";

export class Meter extends Model {
  static type = "meter" as const;

  /** Server-only (no scope). */
  static scope = {};

  static indexes = ["stripeMeterId", "eventName"];

  /** Stripe meter ID (mtr_...). */
  stripeMeterId: string = "";

  /** Display name. */
  displayName: string = "";

  /** The event name clients send via POST /v1/billing/meter-events (e.g. "api_request"). */
  eventName: string = "";

  /** How usage is aggregated. */
  aggregation: MeterAggregation = "sum";

  /**
   * JSON path into the event payload to extract the quantity
   * (Stripe's `default_aggregation.formula`). Default pulls `value`.
   */
  quantityPayloadKey: string = "value";

  /** JSON path to extract the Stripe customer ID (default: `stripe_customer_id`). */
  customerPayloadKey: string = "stripe_customer_id";

  /** Mirrors stripe.Meter.status — "active" or "inactive". */
  status: string = "active";

  metadata: Record<string, string> = {};

  lastSyncedAt: Date | null = null;
}

/**
 * PaymentMethod — a saved payment instrument for a Customer.
 *
 * We store only the non-sensitive bits (brand, last4, exp) — PCI data lives
 * on Stripe. Card updates/deletions go through the Stripe Billing Portal.
 */
import { Model } from "@parcae/model";
import { Customer } from "./Customer";

export type PaymentMethodType =
  | "card"
  | "link"
  | "us_bank_account"
  | "sepa_debit"
  | "au_becs_debit"
  | "bacs_debit"
  | "affirm"
  | "klarna"
  | "afterpay_clearpay"
  | "cashapp";

export class PaymentMethod extends Model {
  static type = "payment_method" as const;

  static scope = {
    read: (ctx: any) =>
      ctx.user ? (qb: any) => qb.where("user", ctx.user.id) : null,
  };

  static indexes = [
    "user",
    "customer",
    "stripePaymentMethodId",
    ["customer", "isDefault"],
  ];

  user: string = "";
  customer!: Customer;

  /** Stripe payment method ID (pm_...). */
  stripePaymentMethodId: string = "";

  paymentMethodType: PaymentMethodType = "card";

  /** Card brand (visa, mastercard, amex, ...). */
  brand: string = "";

  /** Last four digits. */
  last4: string = "";

  /** Card expiration month (1-12). */
  expMonth: number = 0;

  /** Card expiration year (YYYY). */
  expYear: number = 0;

  /** Issuing country code (US, GB, ...). */
  country: string = "";

  /** Wallet type (apple_pay, google_pay, "") if applicable. */
  wallet: string = "";

  /** Whether this is the customer's default payment method. */
  isDefault: boolean = false;

  /** Full billing details (opaque JSONB, matches stripe.BillingDetails). */
  billingDetails: Record<string, any> = {};

  metadata: Record<string, string> = {};

  lastSyncedAt: Date | null = null;
}

/**
 * Price — a specific price point for a Product.
 *
 * A Product can have many Prices (monthly, yearly, metered, tiered, etc.).
 * Amount is stored in the smallest currency unit (cents for USD) to match
 * Stripe's convention exactly.
 */
import { Model } from "@parcae/model";
import { Product } from "./Product";

export type PriceInterval = "day" | "week" | "month" | "year";
export type PriceType = "one_time" | "recurring";
export type UsageType = "licensed" | "metered";

export class Price extends Model {
  static type = "price" as const;

  static scope = {
    read: (ctx: any) => (ctx.user ? () => {} : null),
  };

  static indexes = [
    "product",
    "stripePriceId",
    "active",
    ["product", "active"],
  ];

  /** Stripe price ID (price_...). Set on first sync. */
  stripePriceId: string = "";

  /** The Product this price belongs to. */
  product!: Product;

  /** Display nickname (optional — Stripe exposes this as `nickname`). */
  nickname: string = "";

  /** Amount in minor units (e.g. cents). `null` if the price is tiered/custom. */
  unitAmount: number = 0;

  /** ISO 4217 currency code, lowercase — matches Stripe. */
  currency: string = "usd";

  /** One-time vs recurring. */
  priceType: PriceType = "recurring";

  /** Billing interval (only meaningful for recurring). */
  interval: PriceInterval = "month";

  /** How many intervals per billing cycle (1 month, 3 months, etc.). */
  intervalCount: number = 1;

  /** licensed (per-seat) or metered (usage-based). */
  usageType: UsageType = "licensed";

  /** For metered prices: how Stripe aggregates usage. */
  aggregateUsage: string = "";

  /** Trial duration in days (0 = no trial). */
  trialPeriodDays: number = 0;

  /** Lookup key — stable identifier consumers can reference instead of the generated ID. */
  lookupKey: string = "";

  /** Whether this price is available for new checkouts. */
  active: boolean = true;

  /** Arbitrary metadata that round-trips to Stripe. */
  metadata: Record<string, string> = {};

  /**
   * Raw tiers array for tiered pricing.
   *
   * Stored as JSONB. Each tier has `{ up_to, flat_amount?, unit_amount?,
   * flat_amount_decimal?, unit_amount_decimal? }`. See Stripe docs for
   * details — we don't model this as typed properties because we don't
   * query into it server-side.
   */
  tiers: any[] = [];

  /** Tiers mode: "graduated" or "volume" (only for tiered prices). */
  tiersMode: string = "";

  lastSyncedAt: Date | null = null;
}

/**
 * Product — a billable item in the catalog.
 *
 * Synced bi-directionally with Stripe: admins can create products in either
 * the Stripe Dashboard or through Parcae (e.g. via an admin controller).
 * Webhooks keep the local copy in sync with Stripe; `hook.after(Product, "save")`
 * keeps Stripe in sync with local changes.
 *
 * Source of truth conflicts: Stripe wins on conflicts (webhooks are replayed
 * via the reconcile job as a safety net). The `stripeProductId` field is
 * populated the first time a local product is pushed to Stripe.
 */
import { Model } from "@parcae/model";

export class Product extends Model {
  static type = "product" as const;

  /** Any authenticated user can read the active catalog. Writes go through Stripe. */
  static scope = {
    read: (ctx: any) => (ctx.user ? () => {} : null),
  };

  static indexes = ["stripeProductId", "active", ["active", "updatedAt"]];

  /** Stripe product ID (prod_...). Set on first sync. */
  stripeProductId: string = "";

  /** Display name. */
  name: string = "";

  /** Long description (Markdown allowed). */
  description: string = "";

  /** Feature bullets shown in pricing tables. */
  features: string[] = [];

  /** Marketing image URL (Stripe stores up to 8 images — we keep the first). */
  image: string = "";

  /** Whether the product is available for purchase. Mirrors stripe.Product.active. */
  active: boolean = true;

  /** Arbitrary provider/app metadata (tax code, category, etc.). */
  metadata: Record<string, string> = {};

  /**
   * App-specific flags. These never round-trip to Stripe — useful for marking
   * a product as the "highlighted" option in a pricing table, or flagging
   * token-pack products for the credits grant hook.
   */
  highlight: boolean = false;

  /** When the product was last reconciled from Stripe. */
  lastSyncedAt: Date | null = null;
}

/**
 * PromotionCode — the customer-facing string that redeems a Coupon.
 *
 * Codes like "BLACKFRIDAY25" that users type at checkout. Multiple
 * PromotionCodes can point at the same Coupon (e.g. channel-specific codes
 * for tracking).
 */
import { Model } from "@parcae/model";
import { Coupon } from "./Coupon";

export class PromotionCode extends Model {
  static type = "promotion_code" as const;

  static scope = {
    read: (ctx: any) => (ctx.user ? () => {} : null),
  };

  static indexes = ["stripePromotionCodeId", "code", "coupon", "active"];

  /** Stripe promotion code ID (promo_...). */
  stripePromotionCodeId: string = "";

  /** The redeemable code string (case-insensitive). */
  code: string = "";

  /** The Coupon this code grants. */
  coupon!: Coupon;

  /** Whether the code is redeemable today. */
  active: boolean = true;

  /** Maximum total redemptions across all customers (0 = unlimited). */
  maxRedemptions: number = 0;

  /** Current redemption count. */
  timesRedeemed: number = 0;

  /** Expiration timestamp. */
  expiresAt: Date | null = null;

  /** If true, code is only valid for first-time customers. */
  firstTimeTransaction: boolean = false;

  /** Minimum order amount in minor units. */
  minimumAmount: number = 0;

  /** ISO 4217 currency (for `minimumAmount`). */
  minimumAmountCurrency: string = "usd";

  /** Only redeemable by this specific Customer ID (empty = any customer). */
  restrictToCustomer: string = "";

  metadata: Record<string, string> = {};

  lastSyncedAt: Date | null = null;
}

/**
 * Subscription — a user's active or historical subscription.
 *
 * Line items live on SubscriptionItem (one per Price on the subscription) so
 * that multi-item subscriptions (e.g. seat-based + metered add-on) work
 * correctly. For the common single-item case you can derive the Price via
 * `SubscriptionItem.where({ subscription: sub.id }).first()`.
 *
 * Status values mirror Stripe exactly so no translation layer is required.
 */
import { Model } from "@parcae/model";
import { Customer } from "./Customer";

export type SubscriptionStatus =
  | "incomplete"
  | "incomplete_expired"
  | "trialing"
  | "active"
  | "past_due"
  | "canceled"
  | "unpaid"
  | "paused";

export class Subscription extends Model {
  static type = "subscription" as const;

  static scope = {
    read: (ctx: any) =>
      ctx.user ? (qb: any) => qb.where("user", ctx.user.id) : null,
  };

  static indexes = [
    "user",
    "customer",
    "stripeSubscriptionId",
    "status",
    ["user", "status"],
  ];

  /** Denormalized User ID for scope filtering (matches Customer.user). */
  user: string = "";

  /** The billing Customer this subscription belongs to. */
  customer!: Customer;

  /** Stripe subscription ID (sub_...). */
  stripeSubscriptionId: string = "";

  /** Mirrors stripe.Subscription.status. */
  status: SubscriptionStatus = "incomplete";

  /** Start of the current billing period. */
  currentPeriodStart: Date | null = null;

  /** End of the current billing period (also next invoice date if active). */
  currentPeriodEnd: Date | null = null;

  /** If true, subscription cancels at period end (user initiated cancel). */
  cancelAtPeriodEnd: boolean = false;

  /** Explicit date the subscription was/will be canceled, if known. */
  cancelAt: Date | null = null;

  /** When the subscription was canceled (status transition to "canceled"). */
  canceledAt: Date | null = null;

  /** When the subscription was created in Stripe. */
  stripeCreatedAt: Date | null = null;

  /** Trial start/end dates (null if no trial). */
  trialStart: Date | null = null;
  trialEnd: Date | null = null;

  /** Stripe's default payment method for this subscription. */
  defaultPaymentMethod: string = "";

  /** Collection method: "charge_automatically" or "send_invoice". */
  collectionMethod: string = "charge_automatically";

  /** Latest invoice ID associated with this subscription. */
  latestInvoice: string = "";

  /** Pending update data (schedule changes, etc.) — opaque JSONB. */
  pendingUpdate: Record<string, any> = {};

  /** Cancellation details: reason, feedback, etc. */
  cancellationDetails: Record<string, any> = {};

  /** Metadata that round-trips to Stripe. */
  metadata: Record<string, string> = {};

  lastSyncedAt: Date | null = null;
}

/**
 * SubscriptionItem — a line item on a Subscription.
 *
 * One row per Price on the subscription. Enables multi-item subscriptions
 * (seat-based + metered add-ons, bundles, etc.) and exposes the `quantity`
 * field for seat billing and the `meter` field for usage billing.
 */
import { Model } from "@parcae/model";
import { Subscription } from "./Subscription";
import { Price } from "./Price";

export class SubscriptionItem extends Model {
  static type = "subscription_item" as const;

  static scope = {
    read: (ctx: any) =>
      ctx.user ? (qb: any) => qb.where("user", ctx.user.id) : null,
  };

  static indexes = [
    "subscription",
    "stripeSubscriptionItemId",
    ["subscription", "price"],
  ];

  /** Denormalized user for scope filtering. */
  user: string = "";

  subscription!: Subscription;
  price!: Price;

  /** Stripe subscription item ID (si_...). */
  stripeSubscriptionItemId: string = "";

  /** Quantity (relevant for licensed/seat prices). */
  quantity: number = 1;

  /** Stripe Billing Meter ID (only for metered prices). */
  stripeMeterId: string = "";

  metadata: Record<string, string> = {};

  lastSyncedAt: Date | null = null;
}

/**
 * UsageRecord — a single usage event reported against a Meter.
 *
 * Local record of what was reported to Stripe. Helpful for dashboards and
 * cross-checks with the reconcile job. Stripe is the authoritative source
 * for billable usage — this is a local mirror.
 */
import { Model } from "@parcae/model";
import { SubscriptionItem } from "./SubscriptionItem";

export class UsageRecord extends Model {
  static type = "usage_record" as const;

  static scope = {
    read: (ctx: any) =>
      ctx.user ? (qb: any) => qb.where("user", ctx.user.id) : null,
  };

  static indexes = [
    "user",
    "subscriptionItem",
    "meter",
    ["subscriptionItem", "timestamp"],
  ];

  user: string = "";
  subscriptionItem!: SubscriptionItem;

  /** The Meter this record was reported against (Meter.id). */
  meter: string = "";

  /** Quantity reported. */
  quantity: number = 0;

  /** When the usage occurred. */
  timestamp: Date = new Date();

  /** Idempotency key passed to Stripe. */
  idempotencyKey: string = "";

  /** How Stripe received it: "increment" (default) or "set". */
  action: string = "increment";

  /** Arbitrary metadata attached locally (not sent to Stripe). */
  metadata: Record<string, string> = {};
}

